                     className="w-full bg-indigo-600 text-white py-3.5 rounded-xl font-bold hover:bg-indigo-500 transition-all shadow-lg shadow-indigo-900/50 flex items-center justify-center gap-2 active:scale-95"
                   >
                      <ScanLine size={20} /> 重试 / 开启
                   </button>
                   {cameraError && <p className="text-red-400 text-xs mt-4">{cameraError}</p>}
                </div>
             ) : (
                <>
                   <video ref={videoRef} className="absolute inset-0 w-full h-full object-cover" playsInline muted autoPlay />
                   <canvas ref={canvasRef} className="absolute inset-0 w-full h-full opacity-0" />

                   {/* Scanner Overlay */}
                   <div className="absolute inset-0 pointer-events-none flex flex-col items-center justify-center z-10">
