                   <div className="w-20 h-20 bg-slate-800 rounded-full flex items-center justify-center mb-6 shadow-inner ring-1 ring-white/10">
                      <Camera size={36} className="text-slate-400" />
                   </div>
                   <h3 className="text-white font-bold text-lg mb-2">摄像头已关闭</h3>
                   <p className="text-slate-400 text-sm mb-8">摄像头正在启动...</p>
                   <button 
