import React from 'react';
import QueueManager from './QueueManager';
import { QueueTicket, RegistrationRecord, Staff } from '../types';

interface TrainingCheckinManagerProps {
  queue: QueueTicket[];
  registrationList: RegistrationRecord[];
  onSiteRecords: RegistrationRecord[]; 
  staffList: Staff[];
  onCheckIn: (staffId: string) => void;
  onClearQueue: () => void;
}

const TrainingCheckinManager: React.FC<TrainingCheckinManagerProps> = ({
  queue,
  registrationList,
  onSiteRecords, 
  staffList,
  onCheckIn, 
  onClearQueue, 
}) => {
  // Combine all potential people to check in
  const allPotentialAttendees = [
    ...registrationList,
    ...onSiteRecords,
  ];

  // We might also include PENDING staff who were manually added
  staffList.forEach(staff => {
    if ((staff.status === 'PENDING' || staff.status === 'INTERVIEWED') && !allPotentialAttendees.some(r => r.id === staff.id)) {
      allPotentialAttendees.push({
        id: staff.id,
        registrationNumber: 'STAFF',
        name: staff.name,
        phone: staff.phone,
        idCard: staff.idCard,
        submissionTime: staff.joinDate,
      });
    }
  });

  return (
    <QueueManager 
      queue={queue}
      registrationList={allPotentialAttendees}
      onCheckIn={onCheckIn}
      onClearQueue={onClearQueue}
      onUpdateTicketStatus={() => {}} // This is handled in App.tsx
    />
  );
};

export default TrainingCheckinManager;
