```tsx
import React, { useState, useMemo } from 'react';
import { 
  LayoutDashboard, 
  UserPlus, 
  ClipboardList, 
  TrendingUp,
  PieChart,
  BarChart3,
  ScanLine
} from 'lucide-react';
import { QueueTicket, RegistrationRecord, Staff, FormTemplate, FormSubmission, PermissionSettings, UserSession } from '../types';
import StaffRegistration from './StaffRegistration';
import { ResponsiveContainer, PieChart as RePieChart, Pie, Cell, Tooltip, Legend, BarChart, Bar, XAxis, YAxis, CartesianGrid } from 'recharts';
import QueueManager from './QueueManager';

interface TrainingCheckinManagerProps {
  queue: QueueTicket[];
  registrationList: RegistrationRecord[];
  onSiteRecords: RegistrationRecord[]; 
  onUpdateOnSiteRecords: (records: RegistrationRecord[]) => void;
  staffList: Staff[];
  forms: FormTemplate[];
  formSubmissions: FormSubmission[];
  onCheckIn: (staffId: string) => void;
  onClearQueue: () => void;
  onUpdateRegistration: (records: RegistrationRecord[]) => void;
  onBatchAddStaff: (staffList: Staff[]) => void;
  onManageForm?: (formId: string, mode: 'EDIT' | 'ANALYTICS' | 'PREVIEW') => void;
  permissionSettings: PermissionSettings;
  session: UserSession | null;
}

const TrainingCheckinManager: React.FC<TrainingCheckinManagerProps> = ({
  queue,
  registrationList,
  onSiteRecords,
  onUpdateOnSiteRecords,
  staffList,
  forms,
  formSubmissions,
  onCheckIn,
  onClearQueue,
  onUpdateRegistration,
  onBatchAddStaff,
  onManageForm,
  permissionSettings,
  session
}) => {
  const [activeTab, setActiveTab] = useState<'DASHBOARD' | 'MASTER_LIST' | 'ONSITE' | 'CHECKIN'>('DASHBOARD');

  // STRICT PERMISSION: Only ADMIN sees Master List & On-Site Registration.
  // Leaders/Outsourced staff only see Dashboard and Check-in (Scanner).
  const isAdmin = session?.role === 'ADMIN';
  const showMasterList = isAdmin;
  const showOnSite = isAdmin;

  // --- Statistics Logic ---
  const dashboardStats = useMemo(() => {
    // 1. Total Check-ins
    const checkInCount = queue.length;

    // 2. Total Registered (Master + OnSite) - Deduplicated by ID
    const allIds = new Set([...registrationList.map(r => r.id), ...onSiteRecords.map(r => r.id)]);
    const totalRegistered = allIds.size;

    // 3. Gender Distribution of CHECKED-IN users
    let maleCount = 0;
    let femaleCount = 0;

    // Helper to find person details
    const findPerson = (id: string) => {
      return registrationList.find(r => r.id === id) || 
             onSiteRecords.find(r => r.id === id) || 
             staffList.find(s => s.id === id);
    };

    queue.forEach(ticket => {
      const person = findPerson(ticket.staffId);
      if (person) {
        const g = (person as any).gender; 
        if (g === '男' || g === 'Male') maleCount++;
        else if (g === '女' || g === 'Female') femaleCount++;
      }
    });

    // 4. Check-in Timeline
    const timelineData: Record<string, number> = {};
    queue.forEach(t => {
       if(t.checkInTime) {
         const hour = new Date(t.checkInTime).getHours();
         const key = `${hour}:00`;
         timelineData[key] = (timelineData[key] || 0) + 1;
       }
    });
    const timelineChartData = Object.keys(timelineData).map(k => ({ name: k, count: timelineData[k] })).sort((a,b) => parseInt(a.name) - parseInt(b.name));

    return {
      checkInCount,
      totalRegistered,
      checkInRate: totalRegistered > 0 ? Math.round((checkInCount / totalRegistered) * 100) : 0,
      genderData: [
        { name: '男', value: maleCount },
        { name: '女', value: femaleCount }
      ],
      timelineChartData,
      maleCount,
      femaleCount
    };
  }, [queue, registrationList, onSiteRecords, staffList]);

  // Combine lists for QueueManager lookup
  const allPotentialAttendees = useMemo(() => {
    // Combine lists, preferring Master List info if dupe
    const combined = [...registrationList];
    onSiteRecords.forEach(os => {
      if (!combined.find(r => r.id === os.id)) {
        combined.push(os);
      }
    });
    // Also include Staff who might be pending
    staffList.forEach(s => {
       if ((s.status === 'PENDING' || s.status === 'INTERVIEWED') && !combined.find(r => r.id === s.id)) {
          combined.push({
             id: s.id,
             registrationNumber: 'STAFF',
             name: s.name,
             phone: s.phone,
             idCard: s.idCard,
             gender: '未知', // Default
             submissionTime: s.joinDate,
             notes: '',
             isTalent: false
          });
       }
    });
    return combined;
  }, [registrationList, onSiteRecords, staffList]);

  const COLORS = ['#3b82f6', '#ec4899', '#9ca3af'];

  // Construct tabs dynamically based on settings
  const tabs = [
    { id: 'DASHBOARD', label: '数据看板', icon: LayoutDashboard },
  ];

  // Only show Check-in Management if enabled in settings
  if (permissionSettings.enableCheckIn) {
    tabs.push({ id: 'CHECKIN', label: '签到管理', icon: ScanLine });
  }

  if (showOnSite) {
    tabs.push({ id: 'ONSITE', label: '现场报名', icon: UserPlus });
  }

  if (showMasterList) {
    tabs.push({ id: 'MASTER_LIST', label: '汇总名单', icon: ClipboardList });
  }

  return (
    <div className="space-y-4 md:space-y-6 animate-fade-in pb-20">

      {/* Tab Navigation - Scrollable on mobile */}
      <div className="bg-white p-2 rounded-xl shadow-sm border border-gray-100">
         <div className="flex p-1 bg-gray-100/80 rounded-lg overflow-x-auto w-full no-scrollbar">
            {tabs.map(tab => (
              <button
                key={tab.id}
                onClick={() => setActiveTab(tab.id as any)}
                className={`flex-1 min-w-[100px] flex items-center justify-center gap-2 px-4 py-2.5 rounded-md text-sm font-bold transition-all whitespace-nowrap ${
                  activeTab === tab.id 
                    ? 'bg-white text-indigo-600 shadow-sm' 
                    : 'text-gray-500 hover:text-gray-700 hover:bg-gray-200/50'
                }`}
              >
                <tab.icon size={16} /> {tab.label}
              </button>
            ))}
         </div>
      </div>

      {/* --- DASHBOARD VIEW --- */}
      {activeTab === 'DASHBOARD' && (
        <div className="space-y-4 md:space-y-6">
           <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
              <div className="bg-white p-5 rounded-xl border border-gray-100 shadow-sm">
                 <div className="flex justify-between items-start mb-2">
                    <p className="text-xs font-bold text-gray-400 uppercase">签到人数</p>
                    <div className="p-2 bg-green-50 text-green-600 rounded-lg"><UserCheckIcon size={16} /></div>
                 </div>
                 <h3 className="text-3xl font-black text-gray-800">{dashboardStats.checkInCount}</h3>
                 <p className="text-xs text-gray-400 mt-1">占总报名 {dashboardStats.checkInRate}%</p>
              </div>

              {showOnSite && (
                <div className="bg-white p-5 rounded-xl border border-gray-100 shadow-sm">
                   <div className="flex justify-between items-start mb-2">
                      <p className="text-xs font-bold text-gray-400 uppercase">现场报名</p>
                      <div className="p-2 bg-blue-50 text-blue-600 rounded-lg"><UserPlus size={16} /></div>
                   </div>
                   <h3 className="text-3xl font-black text-gray-800">{onSiteRecords.length}</h3>
                   <p className="text-xs text-gray-400 mt-1">今日新增人员</p>
                </div>
              )}

              {showMasterList && (
                <div className="bg-white p-5 rounded-xl border border-gray-100 shadow-sm">
                   <div className="flex justify-between items-start mb-2">
                      <p className="text-xs font-bold text-gray-400 uppercase">总名单人数</p>
                      <div className="p-2 bg-indigo-50 text-indigo-600 rounded-lg"><ClipboardList size={16} /></div>
                   </div>
                   <h3 className="text-3xl font-black text-gray-800">{registrationList.length}</h3>
                   <p className="text-xs text-gray-400 mt-1">包含历史与导入数据</p>
                </div>
              )}
              <div className="bg-white p-5 rounded-xl border border-gray-100 shadow-sm">
                 <div className="flex justify-between items-start mb-2">
                    <p className="text-xs font-bold text-gray-400 uppercase">待签到</p>
                    <div className="p-2 bg-orange-50 text-orange-600 rounded-lg"><TrendingUp size={16} /></div>
                 </div>
                 <h3 className="text-3xl font-black text-gray-800">{dashboardStats.totalRegistered - dashboardStats.checkInCount}</h3>
                 <p className="text-xs text-gray-400 mt-1">剩余未到场</p>
              </div>
           </div>

           <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
              {/* Gender Chart */}
              <div className="bg-white p-6 rounded-xl border border-gray-100 shadow-sm">
                 <h3 className="font-bold text-gray-800 mb-6 flex items-center gap-2">
                    <PieChart size={18} className="text-pink-500" /> 签到人员性别分布
                 </h3>
                 <div className="h-64 flex items-center justify-center">
                    {dashboardStats.checkInCount > 0 ? (
                      <ResponsiveContainer width="100%" height="100%">
                          <RePieChart>
                            <Pie
                                data={dashboardStats.genderData}
                                cx="50%"
                                cy="50%"
                                innerRadius={60}
                                outerRadius={80}
                                paddingAngle={5}
                                dataKey="value"
                            >
                                {dashboardStats.genderData.map((entry, index) => (
                                  <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                                ))}
                            </Pie>
                            <Tooltip />
                            <Legend verticalAlign="bottom" height={36} iconType="circle" />
                          </RePieChart>
                      </ResponsiveContainer>
                    ) : (
                      <div className="text-gray-400 flex flex-col items-center">
                        <PieChart size={48} className="mb-2 opacity-20" />
                        <p>暂无签到数据</p>
                      </div>
                    )}
                 </div>
                 {/* Gender Text Stats */}
                 <div className="flex justify-center gap-8 mt-4 pt-4 border-t border-gray-50">
                    <div className="text-center">
                       <p className="text-xs text-gray-400 mb-1">男性</p>
                       <p className="font-bold text-blue-600 text-lg">{dashboardStats.maleCount}</p>
                    </div>
                    <div className="text-center">
                       <p className="text-xs text-gray-400 mb-1">女性</p>
                       <p className="font-bold text-pink-500 text-lg">{dashboardStats.femaleCount}</p>
                    </div>
                 </div>
              </div>

              {/* Timeline Chart */}
              <div className="bg-white p-6 rounded-xl border border-gray-100 shadow-sm">
                 <h3 className="font-bold text-gray-800 mb-6 flex items-center gap-2">
                    <BarChart3 size={18} className="text-indigo-500" /> 签到时间段分布
                 </h3>
                 <div className="h-64">
                    {dashboardStats.timelineChartData.length > 0 ? (
                      <ResponsiveContainer width="100%" height="100%">
                          <BarChart data={dashboardStats.timelineChartData}>
                            <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f3f4f6" />
                            <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fontSize: 12, fill: '#9ca3af'}} />
                            <YAxis axisLine={false} tickLine={false} tick={{fontSize: 12, fill: '#9ca3af'}} />
                            <Tooltip cursor={{fill: '#f3f4f6'}} contentStyle={{borderRadius: '8px', border: 'none', boxShadow: '0 4px 12px rgba(0,0,0,0.1)'}} />
                            <Bar dataKey="count" fill="#6366f1" radius={[4, 4, 0, 0]} barSize={20} />
                          </BarChart>
                      </ResponsiveContainer>
                    ) : (
                      <div className="h-full flex flex-col items-center justify-center text-gray-400">
                        <BarChart3 size={48} className="mb-2 opacity-20" />
                        <p>暂无签到数据</p>
                      </div>
                    )}
                 </div>
              </div>
           </div>
        </div>
      )}

      {/* --- CHECK-IN MANAGEMENT VIEW (Only if enabled) --- */}
      {activeTab === 'CHECKIN' && permissionSettings.enableCheckIn && (
        <QueueManager 
          queue={queue}
          registrationList={allPotentialAttendees}
          onCheckIn={onCheckIn}
          onClearQueue={onClearQueue}
        />
      )}

      {/* --- ON-SITE REGISTRATION VIEW (ADMIN ONLY) --- */}
      {activeTab === 'ONSITE' && showOnSite && (
        <StaffRegistration 
          records={onSiteRecords} 
          onUpdateRecords={onUpdateOnSiteRecords} 
          groups={[]} // On-site usually doesn't assign groups immediately
          onBatchAddStaff={onBatchAddStaff} 
          existingStaffList={staffList} 
          forms={forms}
          formSubmissions={formSubmissions}
          onManageForm={onManageForm}
          permissionSettings={permissionSettings}
          displayMode="MASTER" // Simplified view
          allowFormSync={false} // Disable form sync for on-site manual entry focus
          allowExcelImport={false} // Disable excel for on-site manual
          allowManualEntry={true}
        />
      )}

      {/* --- MASTER LIST VIEW (ADMIN ONLY) --- */}
      {activeTab === 'MASTER_LIST' && showMasterList && (
        <StaffRegistration 
          records={registrationList} 
          onUpdateRecords={onUpdateRegistration} 
          groups={[]} 
          onBatchAddStaff={onBatchAddStaff} 
          existingStaffList={staffList} 
          forms={forms}
          formSubmissions={formSubmissions}
          onManageForm={onManageForm}
          permissionSettings={permissionSettings}
          displayMode="ALL"
        />
      )}

    </div>
  );
};

