import React, { useState } from 'react';
import { FormTemplate, FormSubmission, FormField } from '../types';
import { 
  ArrowLeft, 
  Download, 
  BarChart, 
  Users, 
  Calendar,
  Share2,
  PieChart as PieIcon,
  TrendingUp,
  Table,
  FileSpreadsheet,
  Search,
  Eye,
  X,
  PenTool,
  Clock,
  FileText,
  ChevronLeft,
  ChevronRight
} from 'lucide-react';
import { BarChart as ReChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, PieChart, Pie, Cell, Legend, AreaChart, Area, CartesianGrid } from 'recharts';

interface FormAnalyticsProps {
  form: FormTemplate;
  submissions: FormSubmission[];
  onBack: () => void;
  onShare: () => void;
}

const COLORS = ['#6366f1', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6', '#ec4899'];
const ITEMS_PER_PAGE = 9;

const FormAnalytics: React.FC<FormAnalyticsProps> = ({ form, submissions, onBack, onShare }) => {
  const [activeTab, setActiveTab] = useState<'REPORT' | 'INSIGHTS'>('REPORT');
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedSubmission, setSelectedSubmission] = useState<FormSubmission | null>(null);
  const [currentPage, setCurrentPage] = useState(1);

  // --- Derived Data for Insights ---

  // 1. Daily Submission Stats
  const dailyStats = React.useMemo(() => {
    const counts: Record<string, number> = {};
    for(let i=6; i>=0; i--) {
        const d = new Date();
        d.setDate(d.getDate() - i);
        const key = d.toLocaleDateString('zh-CN', { month: '2-digit', day: '2-digit' });
        counts[key] = 0;
    }

    submissions.forEach(s => {
      const date = new Date(s.submittedAt).toLocaleDateString('zh-CN', { month: '2-digit', day: '2-digit' });
      if (counts[date] !== undefined) {
          counts[date]++;
      }
    });
    return Object.keys(counts).map(date => ({ name: date, count: counts[date] }));
  }, [submissions]);

  // 2. Analyze Select Fields
  const selectFieldStats = React.useMemo(() => {
    return form.fields
      .filter(f => f.type === 'SELECT')
      .map(field => {
        const counts: Record<string, number> = {};
        submissions.forEach(s => {
          const val = s.data[field.id] || '未填';
          counts[val] = (counts[val] || 0) + 1;
        });
        const data = Object.keys(counts).map(k => ({ name: k, value: counts[k] }));
        return { fieldName: field.label, data };
      });
  }, [form, submissions]);

  // --- Derived Data for Report ---

  // Smart Column Detection: Prioritize Name, Gender, ID Card, Phone
  const summaryFields = React.useMemo(() => {
    const priorityFields = form.fields.filter(f => 
        f.label.includes('姓名') || f.label.toLowerCase().includes('name') ||
        f.type === 'GENDER' || f.label.includes('性别') ||
        f.type === 'ID_CARD' || f.label.includes('身份证') ||
        f.type === 'PHONE' || f.label.includes('手机')
    );

    // Sort priority: Name > Gender > Phone > ID Card
    priorityFields.sort((a, b) => {
        const getScore = (f: FormField) => {
            if (f.label.includes('姓名') || f.label.toLowerCase().includes('name')) return 4;
            if (f.type === 'GENDER') return 3;
            if (f.type === 'PHONE') return 2;
            if (f.type === 'ID_CARD') return 1;
            return 0;
        };
        return getScore(b) - getScore(a);
    });

    if (priorityFields.length > 0) return priorityFields;

    // Fallback: Just take first 4 fields if no key fields detected
    return form.fields.slice(0, 4);
  }, [form.fields]);

  const filteredSubmissions = React.useMemo(() => {
    return submissions.filter(s => {
       const searchLower = searchTerm.toLowerCase();
