import React, { useState, useEffect } from 'react';
import { User, Lock, ArrowRight, Smartphone, CreditCard, AlertCircle, Check, Zap } from 'lucide-react';
import { AdminUser, Staff, LoginConfig, RegistrationRecord } from '../types';

interface LoginProps {
  staffList: Staff[];
  registrationList: RegistrationRecord[]; // Added to allow candidates to login
  onLogin: (userId: string, role: 'ADMIN' | 'USER') => void;
  adminUsers: AdminUser[];
  loginConfig?: LoginConfig;
}

const Login: React.FC<LoginProps> = ({ staffList, registrationList, onLogin, adminUsers, loginConfig }) => {
  // Login Mode State
  const [loginMode, setLoginMode] = useState<'STAFF' | 'ADMIN'>('STAFF');

  // Form State
  const [formData, setFormData] = useState({
    name: '',
    phone: '',
    idCardSuffix: '', // Last 6 digits
    adminUser: '',
    adminPass: '',
    captchaInput: ''
  });

  const [captchaCode, setCaptchaCode] = useState('');
  const [countdown, setCountdown] = useState(60); 
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  // Status Feedback View
  const [loginStatusView, setLoginStatusView] = useState<'NORMAL' | 'REJECTED' | 'WAITING_GROUP'>('NORMAL');

  // Generate Captcha
  const generateCaptcha = () => {
    const chars = '23456789ABCDEFGHJKLMNPQRSTUVWXYZ';
    let result = '';
    for (let i = 0; i < 4; i++) {
      result += chars.charAt(Math.floor(Math.random() * chars.length));
    }
    setCaptchaCode(result);
    setCountdown(60); 
  };

  // Initial Captcha & Auto Refresh Timer (60s)
  useEffect(() => {
    generateCaptcha();
    const interval = setInterval(() => generateCaptcha(), 60000);
    const countdownInterval = setInterval(() => {
      setCountdown((prev) => (prev > 0 ? prev - 1 : 60));
    }, 1000);

    return () => {
      clearInterval(interval);
      clearInterval(countdownInterval);
    };
  }, []);

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    setLoading(true);
    setTimeout(() => {
        setLoading(false);
        processLogin();
    }, 500);
  };

  const processLogin = () => {
    setLoginStatusView('NORMAL');

    // --- ADMIN LOGIN ---
    if (loginMode === 'ADMIN') {
      if (formData.captchaInput.toUpperCase() !== captchaCode) {
         setError('验证码错误');
         generateCaptcha();
         setFormData({...formData, captchaInput: ''});
         return;
      }
      const admin = adminUsers.find(u => u.username === formData.adminUser && u.password === formData.adminPass);
      if (admin) {
        onLogin(admin.username, 'ADMIN');
      } else {
        setError('账号或密码错误');
        generateCaptcha();
      }
      return;
    }

    // --- STAFF / CANDIDATE LOGIN ---
    const { name, phone, idCardSuffix } = formData;
    if (!name || !phone || !idCardSuffix) {
       setError('请补全信息');
       return;
    }

    // 1. Check Existing Staff List
    let user: Staff | RegistrationRecord | undefined = staffList.find(s => s.name === name && s.phone === phone);
    let userType: 'STAFF' | 'CANDIDATE' = 'STAFF';

    // 2. If not in staff, Check Registration List (Master List)
    if (!user) {
        user = registrationList.find(r => r.name === name && r.phone === phone);
        userType = 'CANDIDATE';
    }

    if (user) {
      // Validate ID Card Suffix
      // Support both 'idCard' property from Staff/RegistrationRecord
      const fullId = (user as any).idCard || '';
      const actualIdSuffix = fullId ? fullId.slice(-6) : '';

      if (actualIdSuffix !== idCardSuffix) {
         setError('身份校验失败，请检查身份证后6位');
         return;
      }

      if (userType === 'STAFF') {
          const s = user as Staff;
          if (s.status === 'REJECTED') {
            setLoginStatusView('REJECTED');
            return;
          }
          // Note: Pending/Interviewed staff will be routed by App.tsx, here we just allow login
      }

      onLogin(user.id, 'USER');
      return;
    } 

    setError('未找到该用户，请检查输入');
  };

  const resetForm = () => {
    setLoginStatusView('NORMAL');
    setFormData({ name: '', phone: '', idCardSuffix: '', adminUser: '', adminPass: '', captchaInput: '' });
    generateCaptcha();
    setError('');
