      <main className={`flex-1 flex flex-col min-h-screen transition-all duration-300 ${!isFullScreen ? 'lg:ml-64' : ''}`}>

        {!isFullScreen && (
          <header className="bg-white border-b border-gray-100 p-4 flex justify-between items-center lg:hidden sticky top-0 z-40 shadow-sm">
             <div className="flex items-center gap-3">
                <button onClick={() => setSidebarOpen(true)} className="text-gray-600 p-1 hover:bg-gray-100 rounded-lg">
                  <Menu size={24} />
                </button>
                <h1 className="font-bold text-gray-800 text-lg">STAFFTool</h1>
             </div>

             <div className="flex items-center gap-2">
                <span className="text-sm font-bold text-gray-700">{session.staff?.name || '管理员'}</span>
             </div>
          </header>
        )}

        {sidebarOpen && !isFullScreen && (
          <div className="fixed inset-0 bg-black/50 z-50 lg:hidden" onClick={() => setSidebarOpen(false)}>
            <div className="bg-slate-900 w-64 h-full shadow-2xl p-4 flex flex-col" onClick={e => e.stopPropagation()}>
               <div className="flex justify-between items-center mb-8 px-2">
                  <span className="text-white font-bold text-xl">STAFFTool</span>
                  <button onClick={() => setSidebarOpen(false)} className="text-slate-400 hover:text-white"><X size={24} /></button>
               </div>

               <nav className="flex-1 space-y-1 overflow-y-auto">
                 {session.role === 'ADMIN' ? (
                   <>
                      <p className="px-4 py-2 text-xs font-semibold text-slate-500 uppercase tracking-wider">管理中心</p>
                      <button onClick={() => { setActiveTab('dashboard'); setSidebarOpen(false); }} className={`w-full text-left px-4 py-3 rounded-xl transition-all ${activeTab === 'dashboard' ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-900/50' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}>
                        <LayoutDashboard size={20} /> <span className="font-medium">工作台</span>
                      </button>
                      <button onClick={() => { setActiveTab('training_checkin'); setSidebarOpen(false); }} className={`w-full text-left px-4 py-3 rounded-xl transition-all ${activeTab === 'training_checkin' || activeTab === 'registration' ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-900/50' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}>
                        <ClipboardCheck size={20} /> <span className="font-medium">报名管理</span>
                      </button>
                      <button onClick={() => { setActiveTab('outsourced'); setSidebarOpen(false); }} className={`w-full text-left px-4 py-3 rounded-xl transition-all ${activeTab === 'outsourced' ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-900/50' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}>
                        <Briefcase size={20} /> <span className="font-medium">分组与编外</span>
                      </button>
                      <button onClick={() => { setActiveTab('form_manager'); setSidebarOpen(false); }} className={`w-full text-left px-4 py-3 rounded-xl transition-all ${activeTab === 'form_manager' || activeTab === 'form_designer' ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-900/50' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}>
                       <FileText size={20} /> <span className="font-medium">表单中心</span>
                     </button>
                     <p className="px-4 mt-6 py-2 text-xs font-semibold text-slate-500 uppercase tracking-wider">行政事务</p>
                      <button onClick={() => { setActiveTab('announcements'); setSidebarOpen(false); }} className={`w-full text-left px-4 py-3 rounded-xl transition-all ${activeTab === 'announcements' ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-900/50' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}>
                        <Megaphone size={20} /> <span className="font-medium">公告通知</span>
                      </button>
                      <button onClick={() => { setActiveTab('reports'); setSidebarOpen(false); }} className={`w-full text-left px-4 py-3 rounded-xl transition-all ${activeTab === 'reports' ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-900/50' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}>
                        <BarChart3 size={20} /> <span className="font-medium">考勤报表</span>
                      </button>
                      <button onClick={() => { setActiveTab('settings'); setSidebarOpen(false); }} className={`w-full text-left px-4 py-3 rounded-xl transition-all ${activeTab === 'settings' ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-900/50' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}>
                        <Settings size={20} /> <span className="font-medium">系统设置</span>
                      </button>
                   </>
                 ) : (
                   <>
                     <button onClick={() => { setActiveTab('dashboard'); setSidebarOpen(false); }} className={`w-full text-left px-4 py-3 rounded-xl transition-all ${activeTab === 'dashboard' ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-900/50' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}>
                       <Home size={20} /> <span className="font-medium">我的主页</span>
                     </button>

                     {canScanCheckIn && (
                        <button onClick={() => { setActiveTab('training_checkin'); setSidebarOpen(false); }} className={`w-full text-left px-4 py-3 rounded-xl transition-all ${activeTab === 'training_checkin' ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-900/50' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}>
                          <ScanLine size={20} /> <span className="font-medium">扫码核销</span>
                        </button>
                     )}

                     {isLeader && (
                        <>
                          <p className="px-4 mt-6 py-2 text-xs font-semibold text-slate-500 uppercase tracking-wider">组长管理</p>
                          <button onClick={() => { setActiveTab('reports'); setSidebarOpen(false); }} className={`w-full text-left px-4 py-3 rounded-xl transition-all ${activeTab === 'reports' ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-900/50' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}>
                            <BarChart3 size={20} /> <span className="font-medium">考勤记录</span>
                          </button>
                          {permissionSettings.allowLeaderBroadcast && (
                             <button onClick={() => { setActiveTab('announcements'); setSidebarOpen(false); }} className={`w-full text-left px-4 py-3 rounded-xl transition-all ${activeTab === 'announcements' ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-900/50' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}>
                               <Megaphone size={20} /> <span className="font-medium">发布公告</span>
                             </button>
                          )}
                        </>
                     )}
                   </>
                 )}
               </nav>
               <div className="p-4 border-t border-slate-800">
                  <div className="flex items-center justify-between gap-3 px-2">
                    <div className="min-w-0">
                       <p className="text-sm font-bold text-white truncate">{session.staff?.name || '管理员'}</p>
                       <p className="text-xs text-slate-500 truncate">{roleDisplayText}</p>
                    </div>
                    <button onClick={handleLogout} className="text-slate-500 hover:text-white transition-colors" title="退出登录">
                       <LogOut size={18} />
                    </button>
                  </div>
               </div>
            </div>
          </div>
        )}

        <div className="flex-1 p-6 md:p-8 overflow-y-auto">
           {renderContent()}
        </div>
      </main>
    </div>
  );
};

export default App;
